import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Building2, Cpu, Hash, AlertTriangle, Thermometer, 
  Phone, User, Clock, CheckCircle, Circle, Loader2,
  Zap, Radio, ShieldAlert, MapPin
} from 'lucide-react';

// ============================================================================
// TYPES
// ============================================================================

export interface ExtractedField {
  id: string;
  label: string;
  value: string | null;
  confidence: number; // 0-100
  icon: React.ElementType;
  required: boolean;
  category: 'identification' | 'problem' | 'context' | 'contact';
}

export interface ExtractionState {
  fields: ExtractedField[];
  completeness: number;
  isExtracting: boolean;
  lastUpdate: number;
}

// ============================================================================
// DEFAULT EXTRACTION FIELDS
// ============================================================================

export const createDefaultFields = (): ExtractedField[] => [
  // Identification
  { id: 'company', label: 'Company', value: null, confidence: 0, icon: Building2, required: true, category: 'identification' },
  { id: 'machine', label: 'Machine Model', value: null, confidence: 0, icon: Cpu, required: true, category: 'identification' },
  { id: 'serial', label: 'Serial Number', value: null, confidence: 0, icon: Hash, required: true, category: 'identification' },

  // Problem
  { id: 'errorCode', label: 'Error Code', value: null, confidence: 0, icon: AlertTriangle, required: true, category: 'problem' },
  { id: 'symptom', label: 'Symptom', value: null, confidence: 0, icon: ShieldAlert, required: true, category: 'problem' },

  // Context
  { id: 'environment', label: 'Environment', value: null, confidence: 0, icon: Thermometer, required: false, category: 'context' },
  { id: 'location', label: 'Location', value: null, confidence: 0, icon: MapPin, required: false, category: 'context' },
  { id: 'urgency', label: 'Urgency Level', value: null, confidence: 0, icon: Clock, required: false, category: 'context' },

  // Contact
  { id: 'contactName', label: 'Contact Name', value: null, confidence: 0, icon: User, required: false, category: 'contact' },
  { id: 'contactPhone', label: 'Contact Phone', value: null, confidence: 0, icon: Phone, required: false, category: 'contact' },
];

// ============================================================================
// EXTRACTION LOGIC
// ============================================================================

interface ExtractionPatterns {
  [key: string]: RegExp[];
}

const EXTRACTION_PATTERNS: ExtractionPatterns = {
  company: [
    /(?:from|at|with|company is|we are|this is|calling from)\s+([A-Z][A-Za-z0-9\s&.-]+(?:GmbH|AG|Inc|LLC|Ltd|Co\.?)?)/gi,
    /([A-Z][A-Za-z0-9]+(?:\s+[A-Z][A-Za-z0-9]+)*)\s+(?:here|speaking)/gi,
    /(DMK|Müller|CLAAS|Kärcher|GEA|KRONE|Jungheinrich|Schubert|Yanmar|Rieter)/gi,
  ],
  machine: [
    /(?:machine|model|equipment|forklift|unit|device)\s+(?:is\s+)?(?:a\s+)?([A-Z0-9][A-Za-z0-9\s-]+)/gi,
    /(EJC|ERE|ETV|ETM|EFG|ECE|ESE)\s*[-\s]?\d+[A-Za-z0-9-]*/gi,
    /(?:Li-Ion|lithium|electric|diesel)\s+([A-Za-z0-9\s-]+)/gi,
  ],
  serial: [
    /(?:serial|serial number|SN|S\/N)\s*(?:is|:)?\s*([A-Z0-9][-A-Z0-9]+)/gi,
    /(?:number|#)\s*([A-Z]{2,3}[-\s]?\d{3,6})/gi,
    /(JH[-\s]?\d{4,6})/gi,
  ],
  errorCode: [
    /(?:error|fault|code|warning|E)\s*(?:code|number|:)?\s*(E?\d{3,5})/gi,
    /(?:showing|displays?|flashing)\s+(?:error\s+)?(E?\d{3,5})/gi,
    /(E0015|E0023|E1147|F\d{3})/gi,
  ],
  symptom: [
    /(?:problem is|issue is|it's|won't|can't|doesn't|stopped|making)\s+(.{10,60})/gi,
    /(grinding|noise|leak|stuck|fail|broken|smoke|vibrat|overheat|not\s+\w+ing)/gi,
    /(hydraulic|lift|battery|motor|wheel|fork|mast|display|sensor)\s+(?:\w+\s+)?(problem|issue|failure|fault)/gi,
  ],
  environment: [
    /(?:indoor|outdoor|warehouse|factory|cold storage|refrigerated|freezer)/gi,
    /(?:temperature|temp)\s*(?:is|around|about)?\s*(-?\d+)\s*(?:degrees|°|C|F)?/gi,
    /(dusty|wet|humid|dry|clean room)/gi,
  ],
  location: [
    /(?:located|location|at|in)\s+([A-Za-z][A-Za-z\s]+(?:,\s*[A-Za-z]+)?)/gi,
    /(?:warehouse|building|hall|zone|area)\s+([A-Z0-9]+)/gi,
    /(Hamburg|Munich|Berlin|Frankfurt|Cologne|Stuttgart)/gi,
  ],
  urgency: [
    /(?:urgent|emergency|critical|asap|immediately|production.?stop|line.?down)/gi,
    /(?:priority|importance)\s*(?:is|:)?\s*(high|medium|low|critical|urgent)/gi,
    /(can wait|not urgent|when.?possible|next week)/gi,
  ],
  contactName: [
    /(?:my name is|this is|I'm|I am|speaking with)\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+)?)/gi,
    /(?:ask for|contact)\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+)?)/gi,
  ],
  contactPhone: [
    /(?:phone|call|reach|number)\s*(?:is|at|:)?\s*([\d\s+-]{8,})/gi,
    /(\+?\d{1,3}[-.\s]?\d{2,4}[-.\s]?\d{3,4}[-.\s]?\d{3,4})/gi,
  ],
};

// Confidence scoring based on pattern match quality
const calculateConfidence = (match: string, pattern: RegExp): number => {
  const baseConfidence = 70;
  let bonus = 0;

  // Longer matches are often more confident
  if (match.length > 10) bonus += 10;
  if (match.length > 20) bonus += 5;

  // Specific patterns get higher confidence
  if (/GmbH|AG|Inc|Ltd/i.test(match)) bonus += 15; // Company suffix
  if (/E\d{4,5}/i.test(match)) bonus += 20; // Error code format
  if (/JH-\d+/i.test(match)) bonus += 20; // Serial format
  if (/EJC|ERE|ETV/i.test(match)) bonus += 15; // Machine model prefix

  return Math.min(98, baseConfidence + bonus);
};

export const extractFromTranscript = (
  transcript: string, 
  currentFields: ExtractedField[]
): ExtractedField[] => {
  const updatedFields = [...currentFields];
  const lowerTranscript = transcript.toLowerCase();

  for (const field of updatedFields) {
    // Skip if already has high-confidence value
    if (field.value && field.confidence > 85) continue;

    const patterns = EXTRACTION_PATTERNS[field.id];
    if (!patterns) continue;

    for (const pattern of patterns) {
      // Reset regex state
      pattern.lastIndex = 0;
      const match = pattern.exec(transcript);

      if (match && match[1]) {
        const extractedValue = match[1].trim();
        const newConfidence = calculateConfidence(extractedValue, pattern);

        // Only update if new confidence is higher
        if (newConfidence > field.confidence) {
          field.value = extractedValue;
          field.confidence = newConfidence;
        }
      } else if (match && !match[1]) {
        // Pattern matched but no capture group - use full match
        const extractedValue = match[0].trim();
        const newConfidence = calculateConfidence(extractedValue, pattern);

        if (newConfidence > field.confidence && field.id === 'urgency') {
          // Map urgency keywords to values
          if (/urgent|emergency|critical|asap|immediately|stop|down/i.test(extractedValue)) {
            field.value = 'Production Stop';
            field.confidence = 90;
          } else if (/can wait|not urgent/i.test(extractedValue)) {
            field.value = 'Low';
            field.confidence = 85;
          }
        }

        if (newConfidence > field.confidence && field.id === 'environment') {
          field.value = extractedValue.charAt(0).toUpperCase() + extractedValue.slice(1);
          field.confidence = newConfidence;
        }
      }
    }
  }

  return updatedFields;
};

export const calculateCompleteness = (fields: ExtractedField[]): number => {
  const requiredFields = fields.filter(f => f.required);
  const filledRequired = requiredFields.filter(f => f.value && f.confidence > 50);

  const requiredScore = (filledRequired.length / requiredFields.length) * 70;

  const optionalFields = fields.filter(f => !f.required);
  const filledOptional = optionalFields.filter(f => f.value && f.confidence > 50);
  const optionalScore = optionalFields.length > 0 
    ? (filledOptional.length / optionalFields.length) * 30 
    : 30;

  return Math.round(requiredScore + optionalScore);
};

// ============================================================================
// COMPONENTS
// ============================================================================

interface ExtractionFieldRowProps {
  field: ExtractedField;
  isNew: boolean;
}

const ExtractionFieldRow: React.FC<ExtractionFieldRowProps> = ({ field, isNew }) => {
  const Icon = field.icon;
  const hasValue = field.value && field.confidence > 50;

  return (
    <motion.div
      initial={isNew ? { x: 20, opacity: 0, scale: 0.95 } : false}
      animate={{ x: 0, opacity: 1, scale: 1 }}
      transition={{ type: "spring", stiffness: 500, damping: 30 }}
      className={`
        flex items-center gap-3 py-2.5 px-3 rounded-lg transition-all duration-300
        ${hasValue 
          ? 'bg-emerald-500/10 border border-emerald-500/20' 
          : 'bg-white/5 border border-white/5'
        }
        ${isNew && hasValue ? 'ring-2 ring-amber-400/50 ring-offset-2 ring-offset-[#0B0C15]' : ''}
      `}
    >
      {/* Icon */}
      <div className={`
        w-8 h-8 rounded-lg flex items-center justify-center shrink-0
        ${hasValue ? 'bg-emerald-500/20' : 'bg-white/5'}
      `}>
        <Icon className={`w-4 h-4 ${hasValue ? 'text-emerald-400' : 'text-slate-500'}`} />
      </div>

      {/* Content */}
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2">
          <span className={`text-[10px] font-bold uppercase tracking-wider ${hasValue ? 'text-emerald-400' : 'text-slate-500'}`}>
            {field.label}
          </span>
          {field.required && !hasValue && (
            <span className="text-[8px] text-amber-400 bg-amber-400/10 px-1.5 py-0.5 rounded border border-amber-400/20">
              REQUIRED
            </span>
          )}
        </div>

        {hasValue ? (
          <motion.div
            initial={{ opacity: 0, y: 5 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-sm font-semibold text-white truncate mt-0.5"
          >
            {field.value}
          </motion.div>
        ) : (
          <div className="text-xs text-slate-600 italic mt-0.5">Listening...</div>
        )}
      </div>

      {/* Status Indicator */}
      <div className="shrink-0">
        {hasValue ? (
          <motion.div
            initial={{ scale: 0, rotate: -180 }}
            animate={{ scale: 1, rotate: 0 }}
            transition={{ type: "spring", stiffness: 500, damping: 25 }}
          >
            <CheckCircle className="w-5 h-5 text-emerald-400" />
          </motion.div>
        ) : (
          <Circle className="w-5 h-5 text-slate-700" />
        )}
      </div>
    </motion.div>
  );
};

interface CompletenessBarProps {
  completeness: number;
  isExtracting: boolean;
}

const CompletenessBar: React.FC<CompletenessBarProps> = ({ completeness, isExtracting }) => {
  const getColor = () => {
    if (completeness >= 80) return 'from-emerald-500 to-emerald-400';
    if (completeness >= 50) return 'from-amber-500 to-amber-400';
    return 'from-rose-500 to-rose-400';
  };

  const getMessage = () => {
    if (completeness >= 90) return 'Ready for dispatch';
    if (completeness >= 70) return 'Good coverage';
    if (completeness >= 50) return 'Gathering details...';
    return 'Listening for key info...';
  };

  return (
    <div className="bg-black/40 rounded-xl p-4 border border-white/10">
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
            Ticket Completeness
          </span>
          {isExtracting && (
            <Loader2 className="w-3 h-3 text-amber-400 animate-spin" />
          )}
        </div>
        <span className={`text-lg font-bold ${completeness >= 80 ? 'text-emerald-400' : completeness >= 50 ? 'text-amber-400' : 'text-rose-400'}`}>
          {completeness}%
        </span>
      </div>

      {/* Progress Bar */}
      <div className="h-2 bg-slate-800 rounded-full overflow-hidden mb-2">
        <motion.div
          initial={{ width: 0 }}
          animate={{ width: `${completeness}%` }}
          transition={{ type: "spring", stiffness: 100, damping: 20 }}
          className={`h-full bg-gradient-to-r ${getColor()} rounded-full relative`}
        >
          {/* Animated shine effect */}
          <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent animate-shimmer" />
        </motion.div>
      </div>

      <p className="text-[11px] text-slate-500">{getMessage()}</p>
    </div>
  );
};

// ============================================================================
// MAIN COMPONENT
// ============================================================================

interface ExtractionPanelProps {
  fields: ExtractedField[];
  completeness: number;
  isExtracting: boolean;
  isConnected: boolean;
  recentlyUpdatedIds?: string[];
}

export const ExtractionPanel: React.FC<ExtractionPanelProps> = ({
  fields,
  completeness,
  isExtracting,
  isConnected,
  recentlyUpdatedIds = [],
}) => {
  // Group fields by category
  const groupedFields = {
    identification: fields.filter(f => f.category === 'identification'),
    problem: fields.filter(f => f.category === 'problem'),
    context: fields.filter(f => f.category === 'context'),
    contact: fields.filter(f => f.category === 'contact'),
  };

  const categoryLabels: Record<string, string> = {
    identification: 'Asset Identification',
    problem: 'Problem Details',
    context: 'Service Context',
    contact: 'Contact Info',
  };

  return (
    <motion.div
      initial={{ opacity: 0, x: 20 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: 20 }}
      className="w-[320px] bg-[#0B0C15]/95 backdrop-blur-xl border-l border-white/10 flex flex-col h-full overflow-hidden"
    >
      {/* Header */}
      <div className="p-4 border-b border-white/10 bg-gradient-to-r from-amber-500/10 to-transparent">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-amber-500 to-amber-600 flex items-center justify-center shadow-lg shadow-amber-500/20">
            <Radio className={`w-5 h-5 text-black ${isConnected ? 'animate-pulse' : ''}`} />
          </div>
          <div>
            <h2 className="font-bold text-white text-sm tracking-wide flex items-center gap-2">
              Live Extraction
              {isConnected && (
                <span className="flex items-center gap-1 text-[9px] text-emerald-400 bg-emerald-500/10 px-2 py-0.5 rounded-full border border-emerald-500/20">
                  <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
                  LIVE
                </span>
              )}
            </h2>
            <p className="text-[10px] text-slate-500 font-mono uppercase tracking-wider">
              AI-Powered Field Detection
            </p>
          </div>
        </div>
      </div>

      {/* Completeness Bar */}
      <div className="p-4 border-b border-white/5">
        <CompletenessBar completeness={completeness} isExtracting={isExtracting} />
      </div>

      {/* Fields List */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6 scrollbar-thin scrollbar-thumb-white/10">
        {Object.entries(groupedFields).map(([category, categoryFields]) => (
          <div key={category}>
            <div className="flex items-center gap-2 mb-3">
              <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">
                {categoryLabels[category]}
              </span>
              <div className="h-px flex-1 bg-white/5" />
            </div>
            <div className="space-y-2">
              {categoryFields.map((field) => (
                <ExtractionFieldRow
                  key={field.id}
                  field={field}
                  isNew={recentlyUpdatedIds.includes(field.id)}
                />
              ))}
            </div>
          </div>
        ))}
      </div>

      {/* Footer */}
      <div className="p-4 border-t border-white/10 bg-black/40">
        <div className="flex items-center justify-between text-[10px]">
          <span className="text-slate-500">
            {fields.filter(f => f.value && f.confidence > 50).length} of {fields.length} fields captured
          </span>
          <span className="text-amber-400 flex items-center gap-1">
            <Zap className="w-3 h-3" /> Powered by AEDIL
          </span>
        </div>
      </div>
    </motion.div>
  );
};

export default ExtractionPanel;
